mapper.select:
select c.*, e.name as masterName, case when curdate() < c.begin_date then '未开班' when curdate() > c.end_date then '已结课' else '已开班' end as status from clazz c left join emp e on c.master_id = e.id
c.name like concat('%', #{name}, '%')
and c.begin_date >= #{begin}
and c.end_date <= #{end}
order by c.update_time desc, c.id desc
